// === TEST CASES ===
// TC1: input { audio_duration: 10, num_files: 2, processing_type: "transcription", premium: false } → output { total: 10, breakdown: { base_cost: 10, premium_multiplier: 1, processing_type: "transcription", rate_per_minute: 0.5, audio_duration: 10, num_files: 2 } }
// TC2: input { audio_duration: 0, num_files: 1, processing_type: "transcription", premium: false } → output { error: "Audio duration must be > 0" }
// TC3: input { audio_duration: -5, num_files: 1, processing_type: "transcription", premium: false } → output { error: "Audio duration must be > 0" }
// TC4: input { audio_duration: 10, num_files: 0, processing_type: "transcription", premium: false } → output { error: "Number of files must be at least 1" }
// TC5: input { audio_duration: 10, num_files: 1, processing_type: "invalid", premium: false } → output { error: "Invalid processing type. Must be one of: transcription, noise_reduction, mixing, mastering" }
// TC6: input { audio_duration: 10, num_files: 1, processing_type: "transcription", premium: true } → output { total: 10, breakdown: { base_cost: 5, premium_multiplier: 2, ... } } (actually 10*0.5*1*2=10)
// TC7: input { audio_duration: 10, num_files: 1, processing_type: "noise_reduction", premium: false } → output { total: 3, breakdown: { base_cost: 3, rate_per_minute: 0.3 } }
// TC8: input { audio_duration: 99999, num_files: 99999, processing_type: "mixing", premium: false } → output { total: 99999*1*99999 = 9999800001? Actually large number, approx 9.9998e12; we don't restrict size }
// TC9: input { audio_duration: 3.7, num_files: 2, processing_type: "mastering", premium: false } → output { total: 3.7*1.5*2 = 11.1, breakdown: base_cost: 11.1 }
// TC10: input { audio_duration: 10, num_files: 1, processing_type: "Transcription", premium: false } → output { total: 5 } (case-insensitive)
// TC11: input { audio_duration: 10, num_files: 1, premium: false } → output { error: "Processing type is required" }
// TC12: input { audio_duration: 10, num_files: 1, processing_type: "transcription", premium: "true" } → output { error: "Premium must be a boolean" }
// TC13: input { audio_duration: 10, num_files: 1, processing_type: "transcription", premium: null } → output { error: "Premium must be a boolean" }
// TC14: input { audio_duration: "10", num_files: 1, processing_type: "transcription", premium: false } → output { error: "Audio duration must be a number" }
// TC15: input { audio_duration: 10, num_files: "1", processing_type: "transcription", premium: false } → output { error: "Number of files must be a number" }
// TC16: input { audio_duration: 10, num_files: 1, processing_type: "transcription", premium: undefined } → output { error: "Premium must be a boolean" }
// TC17: input { audio_duration: 5, num_files: 3, processing_type: "noise_reduction", premium: false } → output { total: 5*0.3*3 = 4.5 }
// TC18: input { audio_duration: 5, num_files: 1, processing_type: "noise reduction", premium: false } → output { error: "Invalid processing type. Must be one of: transcription, noise_reduction, mixing, mastering" }
// TC19: input { audio_duration: 5.5, num_files: 3, processing_type: "noise_reduction", premium: false } → output { total: 5.5*0.3*3 = 4.95 }
// TC20: input { audio_duration: 0.1, num_files: 1, processing_type: "mixing", premium: true } → output { total: 0.1*1*2 = 0.2 }

const calculator = {
  // Rates per minute for each processing type
  RATE_PER_MINUTE: {
    transcription: 0.5,
    noise_reduction: 0.3,
    mixing: 1.0,
    mastering: 1.5
  },

  // Premium quality multiplier
  PREMIUM_MULTIPLIER: 2,

  calculate(inputs) {
    // Validate inputs first
    const validationError = this.validate(inputs);
    if (validationError) {
      return { error: validationError };
    }

    // After validation, all values are clean and normalized
    const audioDuration = Number(inputs.audio_duration);
    const numFiles = Number(inputs.num_files);
    const processingType = String(inputs.processing_type).toLowerCase();
    const premium = Boolean(inputs.premium); // Already validated as real boolean

    const rate = this.RATE_PER_MINUTE[processingType];
    const baseCost = audioDuration * rate * numFiles;
    const premiumMultiplier = premium ? this.PREMIUM_MULTIPLIER : 1;
    const total = baseCost * premiumMultiplier;

    return {
      total: Math.round(total * 100) / 100,
      breakdown: {
        base_cost: Math.round(baseCost * 100) / 100,
        premium_multiplier: premiumMultiplier,
        processing_type: processingType,
        rate_per_minute: rate,
        audio_duration: audioDuration,
        num_files: numFiles
      }
    };
  },

  validate(inputs) {
    // Normalize and check required fields
    const processingType = inputs.processing_type !== undefined ? String(inputs.processing_type).toLowerCase() : undefined;

    // Validate audio_duration
    if (inputs.audio_duration === undefined || inputs.audio_duration === null) {
      return "Audio duration is required";
    }
    if (typeof inputs.audio_duration !== 'number' || isNaN(inputs.audio_duration)) {
      return "Audio duration must be a number";
    }
    if (inputs.audio_duration <= 0) {
      return "Audio duration must be > 0";
    }

    // Validate num_files
    if (inputs.num_files === undefined || inputs.num_files === null) {
      return "Number of files is required";
    }
    if (typeof inputs.num_files !== 'number' || isNaN(inputs.num_files)) {
      return "Number of files must be a number";
    }
    if (inputs.num_files < 1 || !Number.isInteger(inputs.num_files)) {
      return "Number of files must be a positive integer (at least 1)";
    }

    // Validate processing_type
    if (processingType === undefined || processingType === '') {
      return "Processing type is required";
    }
    const allowedTypes = Object.keys(this.RATE_PER_MINUTE);
    if (!allowedTypes.includes(processingType)) {
      return `Invalid processing type. Must be one of: ${allowedTypes.join(', ')}`;
    }

    // Validate premium (must be real boolean)
    if (typeof inputs.premium !== 'boolean') {
      return "Premium must be a boolean";
    }

    // All good
    return null;
  },

  formatCurrency(amount) {
    return '$' + amount.toFixed(2);
  }
};

const CALC_PARAMS = [
  {
    name: 'audio_duration',
    label: 'Audio Duration (minutes)',
    type: 'number',
    placeholder: 'e.g. 10'
  },
  {
    name: 'num_files',
    label: 'Number of Files',
    type: 'number',
    placeholder: 'e.g. 3'
  },
  {
    name: 'processing_type',
    label: 'Processing Type',
    type: 'select',
    options: [
      ['transcription', '📝 Transcription ($0.50/min)'],
      ['noise_reduction', '🔇 Noise Reduction ($0.30/min)'],
      ['mixing', '🎚️ Mixing ($1.00/min)'],
      ['mastering', '🎛️ Mastering ($1.50/min)']
    ]
  },
  {
    name: 'premium',
    label: 'Premium Quality (2x cost)',
    type: 'checkbox'
  }
];
